# Geometry module - shapes, interfaces, and inheritance

interface IShape:
    def area(self) -> float
    ...

interface ITransformable:
    @virtual
    def translate(self, dx: float, dy: float) -> None
    ...

@abstract
class Shape(IShape):
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    @virtual
    def center(self) -> tuple[float, float]:
        return (self.x, self.y)

class Circle(Shape, ITransformable):
    radius: float

    def __init__(self, x: float, y: float, radius: float):
        super().__init__(x, y)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def translate(self, dx: float, dy: float) -> None:
        self.x = self.x + dx
        self.y = self.y + dy

class Rectangle(Shape, ITransformable):
    width: float
    height: float

    def __init__(self, x: float, y: float, width: float, height: float):
        super().__init__(x, y)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def translate(self, dx: float, dy: float) -> None:
        self.x = self.x + dx
        self.y = self.y + dy

    @override
    def center(self) -> tuple[float, float]:
        return (self.x + self.width / 2.0, self.y + self.height / 2.0)

class ShapeGroup(IShape):
    shapes: list[IShape]

    def __init__(self):
        self.shapes = []

    def add(self, shape: IShape) -> None:
        self.shapes.append(shape)

    def area(self) -> float:
        total: float = 0.0
        for s in self.shapes:
            total = total + s.area()
        return total

