# Math utilities module - enums, structs, and static functions

enum ShapeCategory:
    CIRCULAR = 1
    RECTANGULAR = 2
    POLYGONAL = 3
    COMPOSITE = 4

struct Point2D:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    @virtual
    def distance_to(self, other: Point2D) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return (dx * dx + dy * dy) ** 0.5

def classify_shape(area: float) -> ShapeCategory:
    if area < 10.0:
        return ShapeCategory.CIRCULAR
    elif area < 100.0:
        return ShapeCategory.RECTANGULAR
    elif area < 1000.0:
        return ShapeCategory.POLYGONAL
    else:
        return ShapeCategory.COMPOSITE

def format_point(p: Point2D) -> str:
    return "(" + str(p.x) + ", " + str(p.y) + ")"

