# Rendering module - uses geometry and math_utils

from geometry import IShape, Circle, Rectangle, ShapeGroup
from math_utils import Point2D, ShapeCategory, classify_shape

class Renderer:
    rendered_count: int
    total_area: float

    def __init__(self):
        self.rendered_count = 0
        self.total_area = 0.0

    def render(self, shape: IShape, name: str) -> str:
        area: float = shape.area()
        self.total_area = self.total_area + area
        self.rendered_count = self.rendered_count + 1

        cat: ShapeCategory = classify_shape(area)
        cat_name: str = cat.name

        return name + ": area=" + str(area) + ", cat=" + cat_name

    def render_group(self, group: ShapeGroup, items: list[str]) -> list[str]:
        results: list[str] = []
        i: int = 0
        for item in items:
            result: str = "  [" + str(i) + "] " + item
            results.append(result)
            i = i + 1
        return results

    def get_stats(self) -> tuple[int, float]:
        return (self.rendered_count, self.total_area)

def create_sample_circle(cx: float, cy: float, r: float) -> Circle:
    return Circle(cx, cy, r)

def create_sample_rect(x: float, y: float, w: float, h: float) -> Rectangle:
    return Rectangle(x, y, w, h)
